from uni_pc import NoiseScheduleVP, model_wrapper, UniPC


def get_sampling_fn(config, sde, shape, inverse_scaler, eps):
  sampler_name = config.sampling.method
  if sampler_name.lower() == 'uni_pc':
    sampling_fn = get_uni_pc_sampler(sde=sde,
                                  shape=shape,
                                  inverse_scaler=inverse_scaler,
                                  steps=config.sampling.steps,
                                  eps=config.sampling.eps,
                                  skip_type=config.sampling.skip_type,
                                  method=config.sampling.uni_pc_method,
                                  order=config.sampling.uni_pc_order,
                                  denoise=config.sampling.noise_removal,
                                  algorithm_type=config.sampling.algorithm_type,
                                  thresholding=config.sampling.thresholding,
                                  rtol=config.sampling.rtol,
                                  variant=config.sampling.variant,
                                  lower_order_final=config.sampling.lower_order_final,
                                  device=config.device)
  else:
    raise ValueError(f"Sampler name {sampler_name} unknown.")
  return sampling_fn


def get_uni_pc_sampler(sde, shape, inverse_scaler, steps=10, eps=1e-3,
                    skip_type="logSNR", method="multistep", order=3,
                    denoise=False, algorithm_type="data_prediction", thresholding=False,
                    rtol=0.05, atol=0.0078, variant='bh1', lower_order_final=True, device='cuda'):
  """Create a UniPC sampler.
  Args:
    sde: An `sde_lib.SDE` object representing the forward SDE.
    shape: A sequence of integers. The expected shape of a single sample.
    inverse_scaler: The inverse data normalizer.
    steps: number of NFEs (minus one if denoise=True).
    eps: minimum time.
    skip_type: 'logSNR' | 'time_uniform' | 'time_quadratic'.
    method: 'multistep'.
    order: 1 | 2 | 3.
    denoise: whether to denoise to zero at the end.
    algorithm_type: 'data_prediction' | 'noise_prediction'.
    thresholding: dynamic thresholding for pixel-space models.
    rtol/atol: error tolerances (kept for API compatibility).
    variant: 'bh1' | 'bh2' | 'vary_coeff'.
    lower_order_final: use lower order at final steps.
    device: torch device.
  Returns:
    A sampling function that returns samples and the number of function evaluations during sampling.
  """
  ns = NoiseScheduleVP('linear', continuous_beta_0=sde.beta_0, continuous_beta_1=sde.beta_1)

  def uni_pc_sampler(model):
    with torch.no_grad():
      noise_pred_fn = get_noise_fn(sde, model, train=False, continuous=True)
      uni_pc = UniPC(noise_pred_fn, ns, algorithm_type=algorithm_type, correcting_x0_fn="dynamic_thresholding" if thresholding else None, variant=variant)
      x = sde.prior_sampling(shape).to(device)
      x = uni_pc.sample(
        x,
        steps=steps - 1 if denoise else steps,
        t_start=sde.T,
        t_end=eps,
        order=order,
        skip_type=skip_type,
        method=method,
        denoise_to_zero=denoise,
        atol=atol,
        rtol=rtol,
        lower_order_final=lower_order_final,
      )
      return inverse_scaler(x), steps

  return uni_pc_sampler


